--
-- Query  : 06_predict_resolution_fees.sql
-- Title  : Predict — market creation + resolver fee events
-- Kind   : multi_event_by_route
-- Routes : [6, 7]
--          route  6: predict/market_creation_fee — PredictUBIFeeSplitter.FeeSplit(address,string,uint256,uint256,uint256,uint256)
--          route  7: predict/resolver_fee — OptimisticResolver.ResolutionFinalized(uint256,bool,bool) (PENDING DEPLOY)
--
